function solve(nums, queries) {
    const mod = 1000000007;
    let n = nums.length;
    let q = queries.length;
    let factors = new Array(n).fill(1);

    let B = Math.floor(Math.sqrt(n));
    if (B * B < n) B++;

    let smallQueries = new Map();

    for (let i = 0; i < q; i++) {
        let [li, ri, ki, vi] = queries[i];
        if (ki > B) {
            for (let idx = li; idx <= ri; idx += ki) {
                factors[idx] = (factors[idx] * vi) % mod;
            }
        } else {
            let residue_r = li % ki;
            let key = ki + ',' + residue_r;
            if (!smallQueries.has(key)) {
                smallQueries.set(key, []);
            }
            smallQueries.get(key).push([li, ri, vi]);
        }
    }

    for (let [key, qList] of smallQueries.entries()) {
        let [ki, residue_r] = key.split(',').map(Number);
        if (residue_r >= n) continue;

        let L = Math.floor((n - 1 - residue_r) / ki) + 1;
        if (L <= 0) continue;

        let diff = new Array(L+1).fill(1);

        for (let i = 0; i < qList.length; i++) {
            let [li, ri, vi] = qList[i];
            let j0, j1;

            if (residue_r >= li) {
                j0 = 0;
            } else {
                j0 = Math.ceil((li - residue_r) / ki);
            }
            j1 = Math.floor((ri - residue_r) / ki);

            if (j0 >= L) continue;
            if (j1 < 0) continue;
            if (j1 >= L) j1 = L - 1;
            if (j0 > j1) continue;

            diff[j0] = (diff[j0] * vi) % mod;
            if (j1 + 1 < L) {
                let inv_vi = modInverse(vi, mod);
                diff[j1 + 1] = (diff[j1 + 1] * inv_vi) % mod;
            }
        }

        let prod = 1;
        for (let j = 0; j < L; j++) {
            prod = (prod * diff[j]) % mod;
            let idx = residue_r + j * ki;
            factors[idx] = (factors[idx] * prod) % mod;
        }
    }

    for (let i = 0; i < n; i++) {
        nums[i] = (nums[i] * factors[i]) % mod;
    }

    let ans = 0;
    for (let num of nums) {
        ans ^= num;
    }
    return ans;
}

function modInverse(a, modulus) {
    modulus = BigInt(modulus);
    a = BigInt(a);
    let exp = modulus - 2n;
    return Number(modPow(a, exp, modulus));
}

function modPow(base, exponent, modulus) {
    if (modulus === 1n) return 0n;
    let result = 1n;
    base = base % modulus;
    while (exponent > 0n) {
        if (exponent & 1n) {
            result = (result * base) % modulus;
        }
        base = (base * base) % modulus;
        exponent = exponent >> 1n;
    }
    return result;
}
