function modInverse(a, mod) {
    let b = mod - 2;
    a = a % mod;
    let res = 1;
    while (b > 0) {
        if (b & 1) 
            res = (res * a) % mod;
        a = (a * a) % mod;
        b = Math.floor(b / 2);
    }
    return res;
}

