        let k = query[2];
        if (k >= B) {
            large_step.push(query);
        } else {
            small_step.push(query);
        }
    }

    for (let query of large_step) {
        let l = query[0], r = query[1], k = query[2], v = query[3];
        for (let idx = l; idx <= r; idx += k) {
            factors[idx] = (factors[idx] * v) % MOD;
        }
    }

    let queries_by_k = new Array(B);
    for (let i = 0; i < B; i++) {
        queries_by_k[i] = [];
    }
    for (let k = 1; k < B; k++) {
        queries_by_k[k] = new Array(k);
        for (let r = 0; r < k; r++) {
            queries_by_k[k][r] = [];
        }
    }

    for (let query of small_step) {
        let l = query[0], r = query[1], k_val = query[2], v = query[3];
        let residue = l % k_val;
        queries_by_k[k_val][residue].push({l, r, v});
    }

    for (let k = 1; k < B; k++) {
        for (let r = 0; r < k; r++) {
            let list = queries_by_k[k][r];
            if (list.length === 0) continue;
            if (r >= n) continue;
            let L = Math.floor((n - 1 - r) / k) + 1;
            let diff = new Array(L + 2).fill(1);
            for (let q of list) {
                let s = Math.floor((q.l - r) / k);
                let t = Math.floor((q.r - r) / k);
                diff[s] = (diff[s] * q.v) % MOD;
                if (t + 1 < L + 2) {
                    let inv_v;
                    if (invCache.has(q.v)) {
                        inv_v = invCache.get(q.v);
                    } else {
                        inv_v = modInverse(q.v, MOD);
                        invCache.set(q.v, inv_v);
                    }
                    diff[t + 1] = (diff[t + 1] * inv_v) % MOD;
                }
            }
            let current = 1;
            for (let i = 0; i < L; i++) {
                current = (current * diff[i]) % MOD;
                let idx = r + i * k;
                factors[idx] = (factors[idx] * current) % MOD;
            }
        }
    }

    for (let i = 0; i < n; i++) {
        nums[i] = (nums[i] * factors[i]) % MOD;
    }

    let xor = 0;
    for (let num of nums) {
        xor ^= num;
    }
    return xor;
}
