function solve(nums, queries) {
    const mod = 1000000007;
    const n = nums.length;
    const threshold = Math.floor(Math.sqrt(n));

    const residues = [];
    for (let k = 1; k <= threshold; k++) {
        residues[k] = Array.from({ length: k }, () => []);
    }
    for (let k = 1; k <= threshold; k++) {
        for (let i = 0; i < n; i++) {
            residues[k][i % k].push(i);
        }
    }

    const smallFactors = [];
    for (let k = 1; k <= threshold; k++) {
        smallFactors[k] = [];
        for (let r = 0; r < k; r++) {
            const L = residues[k][r].length;
            smallFactors[k][r] = new Array(L + 1).fill(1);
        }
    }

    const result = [...nums];

    function powMod(a, b, mod) {
        a %= mod;
        let res = 1;
        while (b) {
            if (b & 1) res = (res * a) % mod;
            a = (a * a) % mod;
            b = Math.floor(b / 2);
        }
        return res;
    }

    function modInv(a, mod) {
        return powMod(a, mod - 2, mod);
    }

    for (const q of queries) {
        const l = q[0], r = q[1], k = q[2], v = q[3];
        if (k >= threshold) {
            let idx = l;
            while (idx <= r) {
                result[idx] = (result[idx] * v) % mod;
                idx += k;
            }
        } else {
            const residueClass = l % k;
            const arr = residues[k][residueClass];
            let leftIndex = -1, rightIndex = -1;
            let low = 0, high = arr.length - 1;
            while (low <= high) {
                const mid = Math.floor((low + high) / 2);
                if (arr[mid] >= l) {
                    leftIndex = mid;
                    high = mid - 1;
                } else {
                    low = mid + 1;
                }
            }
            if (leftIndex === -1) continue;
            low = 0;
            high = arr.length - 1;
            while (low <= high) {
                const mid = Math.floor((low + high) / 2);
                if (arr[mid] <= r) {
                    rightIndex = mid;
                    low = mid + 1;
                } else {
                    high = mid - 1;
                }
            }
            if (rightIndex === -1) continue;
            smallFactors[k][residueClass][leftIndex] = (smallFactors[k][residueClass][leftIndex] * v) % mod;
            if (rightIndex + 1 < smallFactors[k][residueClass].length) {
                const invV = modInv(v, mod);
                smallFactors[k][residueClass][rightIndex + 1] = (smallFactors[k][residueClass][rightIndex + 1] * invV) % mod;
            }
        }
    }

    for (let k = 1; k <= threshold; k++) {
        for (let r = 0; r < k; r++) {
            const arr = residues[k][r];
            const diff = smallFactors[k][r];
            let cumul = 1;
            for (let j = 0; j < arr.length; j++) {
                cumul = (cumul * diff[j]) % mod;
                const idx = arr[j];
                result[idx] = (result[idx] * cumul) % mod;
            }
        }
    }

    let ans = 0;
    for (let num of result) {
        ans ^= num;
    }
    return ans;
}
